class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        if (k == 1 && n > 1) {
            return -1.0;
        }

        vector<int> mask(1 << n, -1);
        mask[0] = 0;

        double res = -1.0;
        queue<pair<int, double>> q;
        q.push({0, 0});

        while (!q.empty()) {
            int state = q.front().first;
            double curTime = q.front().second;
            q.pop();

            if (__builtin_popcount(state) == n) {
                if (res == -1.0) {
                    res = curTime;
                } else {
                    res = min(res, curTime);
                }
            }

            if (mask[state] != -1 && mask[state] <= curTime) {
                continue;
            }

            mask[state] = curTime;

            int curStage = (int)curTime;
            curStage %= m;

            for (int i = 0; i < n; i++) {
                if ((state & (1 << i)) == 0) {
                    for (int j = 0; j < k; j++) {
                        if (i == j) continue;
                        if ((state & (1 << j)) == 0) break;
                    }

                    int newState = state;
                    vector<int> group;
                    group.push_back(i);

                    for (int j = 0; j < k - 1; j++) {
                        for (int l = 0; l < n; l++) {
                            if ((state & (1 << l)) == 0 && l != i) {
                                newState |= (1 << l);
                                group.push_back(l);
                                break;
                            }
                        }
                    }

                    double crossTime = *max_element(group.begin(), group.end(), 
                        [&time](int a, int b) { return time[a] < time[b]; }) * mul[curStage];

                    int nextStage = (curStage + (int)crossTime) % m;
                    q.push({newState, curTime + crossTime});

                    if (newState != (1 << n) - 1) {
                        for (int l = 0; l < n; l++) {
                            if ((newState & (1 << l)) && !(state & (1 << l))) {
                                int returnTime = time[l] * mul[nextStage];
                                int nextNextStage = (nextStage + (int)returnTime) % m;
                                q.push({state, curTime + crossTime + returnTime});
                                break;
                            }
                        }
                    }
                }
            }
        }

        return res;
    }
};
